#include "pair_sums.h"
#include <stdlib.h>

typedef struct {
    int first;
    int second;
} PairSlot;

bool has_equal_disjoint_pair_sums(const int *values, size_t n, int k) {
    if (values == NULL || n < 4 || k <= 0) {
        return false;
    }

    const int slot_count = 2 * k;
    PairSlot *seen = malloc((size_t)slot_count * sizeof(*seen));
    if (seen == NULL) {
        return false;
    }

    for (int sum = 0; sum < slot_count; sum++) {
        seen[sum].first = -1;
        seen[sum].second = -1;
    }

    for (size_t i = 0; i < n; i++) {
        for (size_t j = i + 1; j < n; j++) {
            const int sum = values[i] + values[j];
            PairSlot *slot = &seen[sum];

            if (slot->first >= 0) {
                const size_t a = (size_t)slot->first;
                const size_t b = (size_t)slot->second;
                if (a != i && a != j && b != i && b != j) {
                    free(seen);
                    return true;
                }
            } else {
                slot->first = (int)i;
                slot->second = (int)j;
            }
        }
    }

    free(seen);
    return false;
}

