static Node *build_range(const int *sorted, size_t begin, size_t end, Node *parent) {
    if (begin >= end) return NULL;
    const size_t middle = begin + (end - begin) / 2;
    Node *root = new_node(sorted[middle], parent);
    if (root == NULL) return NULL;
    root->left = build_range(sorted, begin, middle, root);
    root->right = build_range(sorted, middle + 1, end, root);
    return root;
}

Node *bst_build_balanced(const int *sorted, size_t n) {
    return build_range(sorted, 0, n, NULL);
}

static size_t bst_count(const Node *root) {
    return root == NULL ? 0 : 1 + bst_count(root->left) + bst_count(root->right);
}

static void inorder_fill(const Node *root, int *values, size_t *next) {
    if (root == NULL) return;
    inorder_fill(root->left, values, next);
    values[(*next)++] = root->key;
    inorder_fill(root->right, values, next);
}

Node *bst_rebalance(Node *root) {
    const size_t n = bst_count(root);
    if (n < 2) return root;

    int *values = malloc(n * sizeof(*values));
    if (values == NULL) return root;

    size_t next = 0;
    inorder_fill(root, values, &next);
    bst_free(root);
    Node *balanced = bst_build_balanced(values, n);
    free(values);
    return balanced;
}

static size_t check_balance(const Node *root, bool *ok) {
    if (root == NULL) return 0;
    size_t left = check_balance(root->left, ok);
    size_t right = check_balance(root->right, ok);
    if (left > right + 1 || right > left + 1) *ok = false;
    return left + right + 1;
}

