HeapNode *heap_from_level_order(const int *values, size_t n) {
    if (n == 0) return NULL;
    HeapNode **nodes = calloc(n, sizeof(*nodes));
    if (nodes == NULL) return NULL;
    for (size_t i = 0; i < n; i++) nodes[i] = new_node(values[i], NULL);
